import { useEffect, useMemo, useState } from "react";
import api from "../api";

/** ========= Config ========= **/
const PAGE_SIZE = 10;
const STATUSES = ["PENDING", "PAID", "CANCELED"]; // như cũ

/** Chuẩn hoá Page<?> từ BE */
function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1 };
    return {
        list: d?.content || [],
        pages: typeof d?.totalPages === "number" ? d.totalPages : 1,
    };
}

function emptyForm(contractId) {
    return {
        id: null,
        contractId: contractId ?? null,
        planDate: "",    // ngày dự kiến
        paidDate: "",    // ngày trả (khi đã thu)
        amount: "",      // số tiền
        method: "CASH",  // phương thức: CASH/BANK/OTHER
        note: "",
        status: "PENDING",
        confirmed: false,
    };
}

export default function PaymentsByContract() {
    /** Hợp đồng */
    const [contracts, setContracts] = useState([]);    // [{id, code, customerName, totalAmount}]
    const [contractId, setContractId] = useState(null);

    /** Tổng quan */
    const [summary, setSummary] = useState({ total: 0, paid: 0, remain: 0 });

    /** Bảng đợt thanh toán */
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    /** Modal */
    const [show, setShow] = useState(false);
    const [form, setForm] = useState(emptyForm(null)); // create/update

    /* ==== load contracts & pick first ==== */
    useEffect(() => {
        (async () => {
            try {
                const { data } = await api.get("/api/contracts/simple"); // [{id, code, customerName, totalAmount}]
                setContracts(data || []);
                if (data?.length && !contractId) {
                    setContractId(data[0].id);
                }
            } catch (e) {
                console.error(e);
            }
        })();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    /* ==== khi đổi contract -> load list + summary ==== */
    useEffect(() => {
        if (!contractId) return;
        loadSummary();
        loadBatches();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [contractId, page]);

    async function loadSummary() {
        try {
            const { data } = await api.get(`/api/contracts/${contractId}/payments/summary`);
            setSummary({
                total: data?.total || 0,
                paid: data?.paid || 0,
                remain: Math.max((data?.total || 0) - (data?.paid || 0), 0),
            });
        } catch (e) {
            console.error(e);
            setSummary({ total: 0, paid: 0, remain: 0 });
        }
    }

    async function loadBatches() {
        setLoading(true);
        try {
            const { data } = await api.get(`/api/contracts/${contractId}/payments`, {
                params: { page, size: PAGE_SIZE, sort: "id,desc" },
            });
            const { list, pages } = normalizePage(data);
            setRows(
                list.map((d) => ({
                    id: d.id,
                    code: d.code,                  // nếu bạn có mã đợt
                    planDate: d.planDate,          // LocalDate
                    paidDate: d.paidDate,          // LocalDate
                    amount: d.amount,
                    method: d.method,
                    status: d.status,              // PENDING/PAID/CANCELED
                    confirmed: !!d.confirmed,
                    note: d.note,
                }))
            );
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    /* ==== helpers ==== */
    const fmtMoney = (v) => new Intl.NumberFormat("vi-VN").format(v || 0) + " đ";
    const fmtDate = (d) => (d ? new Date(d).toLocaleDateString("vi-VN") : "-");

    /* ==== CRUD ==== */
    function openCreate() {
        setForm(emptyForm(contractId));
        setShow(true);
    }
    function openEdit(row) {
        setForm({
            id: row.id,
            contractId,
            planDate: row.planDate?.slice(0, 10) || "",
            paidDate: row.paidDate?.slice(0, 10) || "",
            amount: row.amount ?? "",
            method: row.method || "CASH",
            note: row.note || "",
            status: row.status || "PENDING",
            confirmed: !!row.confirmed,
        });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();
        try {
            const payload = {
                contractId: contractId,
                planDate: form.planDate || null,
                paidDate: form.paidDate || null,
                amount: Number(form.amount),
                method: form.method,
                note: form.note?.trim() || null,
                status: form.status,
            };
            if (!form.id) {
                await api.post(`/api/contracts/${contractId}/payments`, payload); // CREATE
            } else {
                await api.put(`/api/contracts/${contractId}/payments/${form.id}`, payload); // UPDATE
            }
            setShow(false);
            if (rows.length === 0 && page > 0) setPage((p) => p - 1);
            await Promise.all([loadSummary(), loadBatches()]);
            alert(!form.id ? "Đã tạo đợt thanh toán" : "Đã cập nhật đợt thanh toán");
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Lưu đợt thanh toán thất bại";
            alert(msg);
        }
    }

    async function confirmPaid(row) {
        if (!window.confirm("Xác nhận đã thu cho đợt này?")) return;
        try {
            await api.post(`/api/contracts/${contractId}/payments/${row.id}/confirm`);
            await Promise.all([loadSummary(), loadBatches()]);
            alert("Đã xác nhận đã thu");
        } catch (err) {
            alert(
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Xác nhận thất bại"
            );
        }
    }

    async function remove(row) {
        if (!window.confirm("Xoá đợt thanh toán này?")) return;
        try {
            await api.delete(`/api/contracts/${contractId}/payments/${row.id}`);
            if (rows.length === 1 && page > 0) setPage((p) => p - 1);
            else await Promise.all([loadSummary(), loadBatches()]);
            alert("Đã xoá");
        } catch (err) {
            alert(err?.response?.data?.message || err?.response?.data?.error || "Xoá thất bại");
        }
    }

    /* ==== UI ==== */
    return (
        <div className="space-y-4">
            <div>
                <h2 className="text-lg font-semibold">Thanh toán</h2>
                <p className="text-sm text-slate-500">Quản lý các đợt thanh toán theo hợp đồng</p>
            </div>

            {/* Tổng quan + chọn HĐ */}
            <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-3 md:flex-1">
                    <div className="bg-white rounded-xl border border-indigo-100 shadow p-4">
                        <div className="text-sm text-slate-500">Tổng giá trị</div>
                        <div className="text-xl font-semibold">{fmtMoney(summary.total)}</div>
                    </div>
                    <div className="bg-white rounded-xl border border-indigo-100 shadow p-4">
                        <div className="text-sm text-slate-500">Đã thu</div>
                        <div className="text-xl font-semibold">{fmtMoney(summary.paid)}</div>
                    </div>
                    <div className="bg-white rounded-xl border border-indigo-100 shadow p-4">
                        <div className="text-sm text-slate-500">Còn lại</div>
                        <div className="text-xl font-semibold">{fmtMoney(summary.remain)}</div>
                    </div>
                </div>

                <div className="flex items-end gap-2">
                    <select
                        className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow min-w-[380px]"
                        value={contractId || ""}
                        onChange={(e) => {
                            setContractId(e.target.value ? Number(e.target.value) : null);
                            setPage(0);
                        }}
                    >
                        {contracts.map((c) => (
                            <option key={c.id} value={c.id}>
                                {c.code} - {c.customerName}
                            </option>
                        ))}
                    </select>

                    <button
                        onClick={openCreate}
                        className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                    >
                        Thêm đợt thanh toán
                    </button>
                </div>
            </div>

            {/* Bảng đợt thanh toán */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Mã HĐ</th>
                            <th className="px-4 py-3 text-left">Ngày dự kiến/Ngày trả</th>
                            <th className="px-4 py-3 text-left">Số tiền</th>
                            <th className="px-4 py-3 text-left">Phương thức</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-left">Xác nhận</th>
                            <th className="px-4 py-3 text-left">Ghi chú</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={8}>Đang tải…</td></tr>
                        ) : rows.length === 0 ? (
                            <tr><td className="px-4 py-6" colSpan={8}>Chưa có dữ liệu</td></tr>
                        ) : rows.map((r) => (
                            <tr key={r.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3 font-medium">{contracts.find(c=>c.id===contractId)?.code || "-"}</td>
                                <td className="px-4 py-3">{fmtDate(r.planDate)} / {fmtDate(r.paidDate)}</td>
                                <td className="px-4 py-3">{fmtMoney(r.amount)}</td>
                                <td className="px-4 py-3">{r.method}</td>
                                <td className="px-4 py-3">
                  <span className={
                      "px-2 py-0.5 rounded-full text-xs " +
                      (r.status === "PAID" ? "bg-emerald-100 text-emerald-700"
                          : r.status === "CANCELED" ? "bg-slate-100 text-slate-700"
                              : "bg-amber-100 text-amber-700")
                  }>
                    {r.status}
                  </span>
                                </td>
                                <td className="px-4 py-3">{r.confirmed ? "Đã xác nhận" : "-"}</td>
                                <td className="px-4 py-3">{r.note || "-"}</td>
                                <td className="px-4 py-3 text-right">
                                    <div className="inline-flex gap-2">
                                        {r.status !== "PAID" && (
                                            <button
                                                onClick={() => confirmPaid(r)}
                                                className="px-2 py-1 rounded bg-emerald-50 text-emerald-700 hover:bg-emerald-100"
                                            >
                                                Đã thu
                                            </button>
                                        )}
                                        <button
                                            onClick={() => openEdit(r)}
                                            className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                        >
                                            Sửa
                                        </button>
                                        <button
                                            onClick={() => remove(r)}
                                            className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                        >
                                            Xóa
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2 justify-center">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={() => setPage((p) => Math.max(0, p - 1))}
                        disabled={page <= 0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page + 1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={() => setPage((p) => p + 1)}
                        disabled={page + 1 >= totalPages}>Sau →</button>
            </div>

            {/* Modal tạo/sửa đợt */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{form.id ? "Sửa đợt thanh toán" : "Thêm đợt thanh toán"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>Đóng</button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Ngày dự kiến</label>
                                <input type="date" value={form.planDate}
                                       onChange={(e)=>setForm((f)=>({...f, planDate: e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Ngày trả</label>
                                <input type="date" value={form.paidDate}
                                       onChange={(e)=>setForm((f)=>({...f, paidDate: e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Số tiền</label>
                                <input type="number" min="0" step="1000" value={form.amount}
                                       onChange={(e)=>setForm((f)=>({...f, amount: e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" required />
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Phương thức</label>
                                <select value={form.method}
                                        onChange={(e)=>setForm((f)=>({...f, method: e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    <option value="CASH">CASH</option>
                                    <option value="BANK">BANK</option>
                                    <option value="OTHER">OTHER</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select value={form.status}
                                        onChange={(e)=>setForm((f)=>({...f, status: e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                                </select>
                            </div>
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Ghi chú</label>
                                <textarea value={form.note}
                                          onChange={(e)=>setForm((f)=>({...f, note: e.target.value}))}
                                          rows={3}
                                          className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" />
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                        onClick={()=>setShow(false)}>Huỷ</button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
